INSERT INTO "MenuItems" ("CategoryId", "Name", "Description", "Price", "DiscountPrice", "Image", "IsVeg", "IsAvailable", "IsFeatured", "PreparationTime", "Status", "DisplayOrder", "CreatedDate", "UpdatedDate") SELECT matched.category_id, matched.item_name, matched.description, matched.price, NULL, matched.image_path, matched.is_veg, TRUE, FALSE, 0, TRUE, matched.display_order, NOW(), NOW() FROM matched WHERE NOT EXISTS (SELECT 1 FROM "MenuItems" m WHERE m."CategoryId" = matched.category_id AND LOWER(m."Name") = LOWER(matched.item_name));
